        "question": [
          "top instruments comparison"
        ],
        "sql": [
          "-- Step 1: Define Date Parameters & \"Kill Switch\" for Weekends\r\n",
          "WITH date_params AS (\r\n",
          "    SELECT\r\n",
          "        CAST(date_format(date_sub(current_date(), 1), 'yyyyMMdd') AS INT) AS yesterday_id,\r\n",
          "        CAST(date_format(date_sub(current_date(), 10), 'yyyyMMdd') AS INT) AS start_7d_id,\r\n",
          "        CAST(date_format(date_sub(current_date(), 43), 'yyyyMMdd') AS INT) AS start_30d_id\r\n",
          "    WHERE dayofweek(date_sub(current_date(), 1)) NOT IN (1, 7)\r\n",
          "),\r\n",
          "\r\n",
          "-- Step 2: Pre-Aggregate Daily Data (+ Active Users & Revenue)\r\n",
          "daily_stats AS (\r\n",
          "    SELECT\r\n",
          "        c.InstrumentID,\r\n",
          "        c.InstrumentName,\r\n",
          "        c.InstrumentDisplayName,\r\n",
          "        c.DateID,\r\n",
          "        SUM(c.Volume) AS Daily_Volume,\r\n",
          "        SUM(CASE \r\n",
          "            WHEN c.IsCopy = false AND c.OpenOrClose = 'Open Click' \r\n",
          "            THEN c.Click ELSE 0 \r\n",
          "        END) AS Daily_Manual_Clicks,\r\n",
          "        COUNT(DISTINCT CASE \r\n",
          "            WHEN c.IsCopy = false AND c.OpenOrClose = 'Open Click' \r\n",
          "            THEN c.CID \r\n",
          "        END) AS Daily_Active_Users,\r\n",
          "        SUM(c.FullCommission) AS Daily_Revenue\r\n",
          "    FROM\r\n",
          "        main.dealing.gold_sql_dp_prod_we_dealing_dbo_dealing_clicks_openclose_breakdown c\r\n",
          "    CROSS JOIN date_params dp\r\n",
          "    WHERE\r\n",
          "        c.DateID > dp.start_30d_id \r\n",
          "        AND c.DateID <= dp.yesterday_id\r\n",
          "        AND c.HedgeServerID != 35\r\n",
          "        AND dayofweek(TO_DATE(CAST(c.DateID AS STRING), 'yyyyMMdd')) NOT IN (1, 7)\r\n",
          "        AND (\r\n",
          "            (c.OpenOrClose = 'Open Click' AND c.IsAirDrop = false) \r\n",
          "            OR c.OpenOrClose = 'Close Click'\r\n",
          "        )\r\n",
          "    GROUP BY c.InstrumentID, c.InstrumentName, c.InstrumentDisplayName, c.DateID\r\n",
          "),\r\n",
          "\r\n",
          "-- Step 3: Identify Top 5 Instruments\r\n",
          "top_5_instruments AS (\r\n",
          "    SELECT InstrumentID, InstrumentDisplayName\r\n",
          "    FROM daily_stats ds\r\n",
          "    CROSS JOIN date_params dp\r\n",
          "    WHERE ds.DateID > dp.start_7d_id \r\n",
          "    GROUP BY InstrumentID, InstrumentDisplayName\r\n",
          "    ORDER BY SUM(ds.Daily_Volume) DESC\r\n",
          "    LIMIT 5\r\n",
          "),\r\n",
          "\r\n",
          "-- Step 4: Final Aggregation\r\n",
          "final_stats AS (\r\n",
          "    SELECT\r\n",
          "        ds.InstrumentDisplayName,\r\n",
          "\r\n",
          "        -- Volume\r\n",
          "        SUM(CASE WHEN ds.DateID = dp.yesterday_id THEN ds.Daily_Volume ELSE 0 END) AS Vol_Yesterday,\r\n",
          "        AVG(CASE WHEN ds.DateID > dp.start_7d_id THEN ds.Daily_Volume END) AS Avg_Vol_7d,\r\n",
          "        AVG(CASE WHEN ds.DateID > dp.start_30d_id THEN ds.Daily_Volume END) AS Avg_Vol_30d,\r\n",
          "\r\n",
          "        -- Manual Clicks\r\n",
          "        SUM(CASE WHEN ds.DateID = dp.yesterday_id THEN ds.Daily_Manual_Clicks ELSE 0 END) AS Manual_Clicks_Yesterday,\r\n",
          "        AVG(CASE WHEN ds.DateID > dp.start_7d_id THEN ds.Daily_Manual_Clicks END) AS Avg_Clicks_7d,\r\n",
          "        AVG(CASE WHEN ds.DateID > dp.start_30d_id THEN ds.Daily_Manual_Clicks END) AS Avg_Clicks_30d,\r\n",
          "\r\n",
          "        -- Active Users\r\n",
          "        SUM(CASE WHEN ds.DateID = dp.yesterday_id THEN ds.Daily_Active_Users ELSE 0 END) AS Active_Users_Yesterday,\r\n",
          "        AVG(CASE WHEN ds.DateID > dp.start_7d_id THEN ds.Daily_Active_Users END) AS Avg_Active_Users_7d,\r\n",
          "        AVG(CASE WHEN ds.DateID > dp.start_30d_id THEN ds.Daily_Active_Users END) AS Avg_Active_Users_30d,\r\n",
          "\r\n",
          "        -- Revenue\r\n",
          "        SUM(CASE WHEN ds.DateID = dp.yesterday_id THEN ds.Daily_Revenue ELSE 0 END) AS Revenue_Yesterday,\r\n",
          "        AVG(CASE WHEN ds.DateID > dp.start_7d_id THEN ds.Daily_Revenue END) AS Avg_Revenue_7d,\r\n",
          "        AVG(CASE WHEN ds.DateID > dp.start_30d_id THEN ds.Daily_Revenue END) AS Avg_Revenue_30d\r\n",
          "\r\n",
          "    FROM daily_stats ds\r\n",
          "    JOIN top_5_instruments t5 ON ds.InstrumentID = t5.InstrumentID\r\n",
          "    CROSS JOIN date_params dp\r\n",
          "    GROUP BY 1\r\n",
          ")\r\n",
          "\r\n",
          "-- Step 5: Final Selection\r\n",
          "SELECT\r\n",
          "    InstrumentDisplayName,\r\n",
          "\r\n",
          "    -- VOLUME METRICS\r\n",
          "    Vol_Yesterday,\r\n",
          "    CAST(Avg_Vol_7d AS BIGINT) AS Avg_Vol_7d,\r\n",
          "    (Vol_Yesterday - CAST(Avg_Vol_7d AS BIGINT)) AS Diff_Vol_vs_7d_Avg,\r\n",
          "    ((Vol_Yesterday / NULLIF(Avg_Vol_7d, 0)) - 1) * 100 AS Pct_Change_Vol_vs_7d,\r\n",
          "    CAST(Avg_Vol_30d AS BIGINT) AS Avg_Vol_30d,\r\n",
          "    (Vol_Yesterday - CAST(Avg_Vol_30d AS BIGINT)) AS Diff_Vol_vs_30d_Avg,\r\n",
          "    ((Vol_Yesterday / NULLIF(Avg_Vol_30d, 0)) - 1) * 100 AS Pct_Change_Vol_vs_30d,\r\n",
          "\r\n",
          "    -- MANUAL CLICK METRICS\r\n",
          "    Manual_Clicks_Yesterday,\r\n",
          "    CAST(Avg_Clicks_7d AS BIGINT) AS Avg_Clicks_7d,\r\n",
          "    (Manual_Clicks_Yesterday - CAST(Avg_Clicks_7d AS BIGINT)) AS Diff_Clicks_vs_7d_Avg,\r\n",
          "    ((Manual_Clicks_Yesterday / NULLIF(Avg_Clicks_7d, 0)) - 1) * 100 AS Pct_Change_Clicks_vs_7d,\r\n",
          "    CAST(Avg_Clicks_30d AS BIGINT) AS Avg_Clicks_30d,\r\n",
          "    (Manual_Clicks_Yesterday - CAST(Avg_Clicks_30d AS BIGINT)) AS Diff_Clicks_vs_30d_Avg,\r\n",
          "    ((Manual_Clicks_Yesterday / NULLIF(Avg_Clicks_30d, 0)) - 1) * 100 AS Pct_Change_Clicks_vs_30d,\r\n",
          "\r\n",
          "    -- ACTIVE USERS METRICS\r\n",
          "    Active_Users_Yesterday,\r\n",
          "    CAST(Avg_Active_Users_7d AS BIGINT) AS Avg_Active_Users_7d,\r\n",
          "    (Active_Users_Yesterday - CAST(Avg_Active_Users_7d AS BIGINT)) AS Diff_Users_vs_7d_Avg,\r\n",
          "    ((Active_Users_Yesterday / NULLIF(Avg_Active_Users_7d, 0)) - 1) * 100 AS Pct_Change_Users_vs_7d,\r\n",
          "    CAST(Avg_Active_Users_30d AS BIGINT) AS Avg_Active_Users_30d,\r\n",
          "    (Active_Users_Yesterday - CAST(Avg_Active_Users_30d AS BIGINT)) AS Diff_Users_vs_30d_Avg,\r\n",
          "    ((Active_Users_Yesterday / NULLIF(Avg_Active_Users_30d, 0)) - 1) * 100 AS Pct_Change_Users_vs_30d,\r\n",
          "\r\n",
          "    -- REVENUE METRICS\r\n",
          "    Revenue_Yesterday,\r\n",
          "    CAST(Avg_Revenue_7d AS BIGINT) AS Avg_Revenue_7d,\r\n",
          "    (Revenue_Yesterday - CAST(Avg_Revenue_7d AS BIGINT)) AS Diff_Revenue_vs_7d_Avg,\r\n",
          "    ((Revenue_Yesterday / NULLIF(Avg_Revenue_7d, 0)) - 1) * 100 AS Pct_Change_Revenue_vs_7d,\r\n",
          "    CAST(Avg_Revenue_30d AS BIGINT) AS Avg_Revenue_30d,\r\n",
          "    (Revenue_Yesterday - CAST(Avg_Revenue_30d AS BIGINT)) AS Diff_Revenue_vs_30d_Avg,\r\n",
          "    ((Revenue_Yesterday / NULLIF(Avg_Revenue_30d, 0)) - 1) * 100 AS Pct_Change_Revenue_vs_30d\r\n",
          "\r\n",
          "FROM final_stats\r\n",
          "ORDER BY Vol_Yesterday DESC;"
        ]
      },
